## hooks/useCamera.ts

I've enhanced the `setupCamera` function to catch specific error names like `NotReadableError` (often caused by the camera being busy) and `NotFoundError`. It now provides distinct, helpful messages for each case instead of a generic fallback. I also explicitly set `audio: false` in the constraints to prevent conflicts with the separate microphone stream used for commentary.

```typescript
import { useState, useEffect, useRef, useCallback } from 'react';

type CameraState = 'inactive' | 'active' | 'error';
type PermissionState = 'checking' | 'prompt' | 'granted' | 'denied';

export const useCamera = () => {
    const [cameraState, setCameraState] = useState<CameraState>('inactive');
    const [permissionStatus, setPermissionStatus] = useState<PermissionState>('checking');
    const [cameraError, setCameraError] = useState<string | null>(null);
    const [videoDevices, setVideoDevices] = useState<MediaDeviceInfo[]>([]);
    const [currentDeviceIndex, setCurrentDeviceIndex] = useState(0);

    const videoRef = useRef<HTMLVideoElement>(null);
    const streamRef = useRef<MediaStream | null>(null);

    useEffect(() => {
        const checkPermissions = async () => {
            if (!navigator.permissions?.query) {
                console.warn('Permissions API not supported, defaulting to prompt behavior.');
                setPermissionStatus('prompt');
                return;
            }
            try {
                const status = await navigator.permissions.query({ name: 'camera' as PermissionName });
                setPermissionStatus(status.state);
                status.onchange = () => setPermissionStatus(status.state);
            } catch (e) {
                console.error("Failed to query camera permissions, defaulting to prompt.", e);
                setPermissionStatus('prompt');
            }
        };
        checkPermissions();
    }, []);

    const setupCamera = useCallback(async (deviceId?: string) => {
        if (streamRef.current) {
            streamRef.current.getTracks().forEach(track => track.stop());
        }
        setCameraError(null);
        setCameraState('inactive');

        try {
            if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
                setCameraError("Your browser does not support camera access.");
                setCameraState('error');
                return;
            }

            // Explicitly set audio to false to avoid conflicts with Live API microphone usage
            const constraints: MediaStreamConstraints = {
                video: deviceId ? { deviceId: { exact: deviceId } } : true,
                audio: false
            };

            const stream = await navigator.mediaDevices.getUserMedia(constraints);
            streamRef.current = stream;
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }
            setCameraState('active');

            if (videoDevices.length === 0) {
                try {
                    const devices = await navigator.mediaDevices.enumerateDevices();
                    const availableVideoDevices = devices.filter(d => d.kind === 'videoinput');
                    setVideoDevices(availableVideoDevices);
                } catch (e) {
                    console.warn("Failed to enumerate devices:", e);
                }
            }
        } catch (err: any) {
            console.error("Error accessing camera:", err);

            let errorMessage = "Could not access camera.";

            if (err.name === "NotAllowedError" || err.name === "PermissionDeniedError") {
                errorMessage = "Permission to use the camera was denied. Please allow camera access in your browser settings and reload the page.";
                setPermissionStatus('denied');
            } else if (err.name === "NotFoundError" || err.name === "DevicesNotFoundError") {
                errorMessage = "No camera device found. Please ensure a camera is connected.";
            } else if (err.name === "NotReadableError" || err.name === "TrackStartError") {
                errorMessage = "The camera is currently in use by another application (e.g., Zoom, Meet) or cannot be accessed. Please close other apps and try again.";
            } else if (err.name === "OverconstrainedError" || err.name === "ConstraintNotSatisfiedError") {
                errorMessage = "The requested camera constraints could not be satisfied. Please try a different camera.";
            } else if (err.message) {
                errorMessage = `Camera Error: ${err.message} (${err.name})`;
            }

            setCameraError(errorMessage);
            setCameraState('error');
        }
    }, [videoDevices.length]);

    const handleStartCamera = useCallback(() => {
        setupCamera();
    }, [setupCamera]);

    const toggleCamera = useCallback(() => {
        if (videoDevices.length > 1) {
            const nextIndex = (currentDeviceIndex + 1) % videoDevices.length;
            setCurrentDeviceIndex(nextIndex);
            setupCamera(videoDevices[nextIndex].deviceId);
        }
    }, [currentDeviceIndex, setupCamera, videoDevices]);

    useEffect(() => {
        // Cleanup function to stop camera when the component unmounts
        return () => {
            if (streamRef.current) {
                streamRef.current.getTracks().forEach(track => track.stop());
            }
        };
    }, []);

    return {
        videoRef,
        streamRef,
        cameraState,
        permissionStatus,
        cameraError,
        videoDevices,
        handleStartCamera,
        toggleCamera,
        setupCamera
    };
};

Of course. The screen freezing when pressing "Replay" is likely caused by the video recorder trying to use a video codec (HEVC/hvc1) that, while technically "supported" by the browser, can cause hardware decoding hangs or heavy CPU usage during blob creation and playback in certain environments.

I will switch the recording service to use the industry-standard `video/webm` (VP9 or VP8) format, which is much more stable for web-based recording and playback. I'll also add safeguards to the replay logic in the Match Screen.

